import{_ as s,c as t,o as n,a1 as e}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"快速開始: 5 分鐘上手 | Plannotator","description":"學習 Plannotator 的安裝和設定方法。在 5 分鐘內完成 CLI 安裝，設定 Claude Code 或 OpenCode 外掛，掌握計畫審查和程式碼審查流程。","frontmatter":{"title":"快速開始: 5 分鐘上手 | Plannotator","sidebarTitle":"5 分鐘上手","subtitle":"快速開始：5 分鐘上手 Plannotator","description":"學習 Plannotator 的安裝和設定方法。在 5 分鐘內完成 CLI 安裝，設定 Claude Code 或 OpenCode 外掛，掌握計畫審查和程式碼審查流程。","tags":["快速開始","入門","安裝","Claude Code","OpenCode"],"order":1},"headers":[],"relativePath":"zh-tw/backnotprop/plannotator/start/getting-started/index.md","filePath":"zh-tw/backnotprop/plannotator/start/getting-started/index.md"}'),o={name:"zh-tw/backnotprop/plannotator/start/getting-started/index.md"};function l(i,a,p,r,d,c){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="快速開始-5-分鐘上手-plannotator" tabindex="-1">快速開始：5 分鐘上手 Plannotator <a class="header-anchor" href="#快速開始-5-分鐘上手-plannotator" aria-label="Permalink to &quot;快速開始：5 分鐘上手 Plannotator&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>✅ 瞭解 Plannotator 的核心功能和使用情境</li><li>✅ 在 5 分鐘內完成 Plannotator 安裝</li><li>✅ 設定 Claude Code 或 OpenCode 整合</li><li>✅ 完成首次計畫審查和程式碼審查</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p><strong>Plannotator</strong> 是一個為 Claude Code 和 OpenCode 設計的互動式審查工具，可以幫你解決以下問題：</p><p><strong>痛點 1</strong>：AI 產生的實施計畫在終端機裡閱讀，文字量大、結構不清晰，審查起來很累。</p><p><strong>痛點 2</strong>：想給 AI 回饋時，只能用文字描述「刪除第 3 段」、「修改這個函式」，溝通成本高。</p><p><strong>痛點 3</strong>：程式碼審查時，需要開啟多個終端機或 IDE，來回切換，難以集中注意力。</p><p><strong>痛點 4</strong>：團隊成員想參與審查，但不知道如何共享計畫內容。</p><p><strong>Plannotator 能幫你</strong>：</p><ul><li>視覺化 UI 取代終端機閱讀，結構清晰</li><li>選取文字即可新增註解（刪除、取代、評論），精確回饋</li><li>Git diff 視覺化審查，支援行級註解</li><li>URL 分享功能，無需後端即可團隊協作</li></ul><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><p><strong>使用情境</strong>：</p><ul><li>使用 Claude Code 或 OpenCode 進行 AI 輔助開發</li><li>需要審查 AI 產生的實施計畫</li><li>需要審查程式碼變更</li><li>需要與團隊成員共享計畫或程式碼審查結果</li></ul><p><strong>不適用情境</strong>：</p><ul><li>純手工撰寫程式碼（不涉及 AI 產生計畫）</li><li>已經有完整的程式碼審查流程（如 GitHub PR）</li><li>不需要視覺化審查工具</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="plannotator-是什麼" tabindex="-1">Plannotator 是什麼 <a class="header-anchor" href="#plannotator-是什麼" aria-label="Permalink to &quot;Plannotator 是什麼&quot;">​</a></h3><p><strong>Plannotator</strong> 是一個為 AI Coding Agent（Claude Code、OpenCode）設計的互動式審查工具，主要提供兩大功能：</p><ol><li><strong>計畫審查</strong>：視覺化審查 AI 產生的實施計畫，支援新增註解、批准或拒絕</li><li><strong>程式碼審查</strong>：視覺化審查 Git diff，支援行級註解和多種檢視模式</li></ol><h3 id="運作原理" tabindex="-1">運作原理 <a class="header-anchor" href="#運作原理" aria-label="Permalink to &quot;運作原理&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (產生計畫)    │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Plannotator   │  ← 本機 HTTP 伺服器</span></span>
<span class="line"><span>│  (視覺化 UI)   │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  瀏覽器        │</span></span>
<span class="line"><span>│  (使用者審查)  │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><p><strong>核心流程</strong>：</p><ol><li>AI Agent 完成計畫或程式碼變更</li><li>Plannotator 在本機啟動 HTTP 伺服器，開啟瀏覽器</li><li>使用者在瀏覽器中檢視計畫/程式碼，新增註解</li><li>使用者批准或拒絕，Plannotator 將決策回傳給 AI Agent</li><li>AI Agent 根據回饋繼續實施或修改</li></ol><h3 id="安全性" tabindex="-1">安全性 <a class="header-anchor" href="#安全性" aria-label="Permalink to &quot;安全性&quot;">​</a></h3><p><strong>所有資料本機處理</strong>，不會上傳到雲端：</p><ul><li>計畫內容、程式碼 diff、註解都儲存在你的本機電腦</li><li>本機 HTTP 伺服器使用隨機連接埠（或固定連接埠）</li><li>URL 分享功能透過壓縮資料到 URL hash 中實現，無需後端</li></ul><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><p><strong>系統需求</strong>：</p><ul><li>作業系統：macOS / Linux / Windows / WSL</li><li>執行環境：Bun（安裝腳本會自動處理）</li><li>AI 環境：Claude Code 2.1.7+ 或 OpenCode</li></ul><p><strong>安裝方式選擇</strong>：</p><ul><li>如果使用 Claude Code：需要安裝 CLI + 外掛</li><li>如果使用 OpenCode：需要設定外掛</li><li>如果只做程式碼審查：只需安裝 CLI</li></ul><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-安裝-plannotator-cli" tabindex="-1">第 1 步：安裝 Plannotator CLI <a class="header-anchor" href="#第-1-步-安裝-plannotator-cli" aria-label="Permalink to &quot;第 1 步：安裝 Plannotator CLI&quot;">​</a></h3><p><strong>macOS / Linux / WSL</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://plannotator.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p><strong>Windows PowerShell</strong>：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plannotator.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p><strong>Windows CMD</strong>：</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsSL https://plannotator.ai/install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> del install.cmd</span></span></code></pre></div><p><strong>你應該看到</strong>：安裝腳本會自動下載 Plannotator CLI 並將其加入系統路徑中，並顯示版本號（如 &quot;plannotator v0.6.7 installed to ...&quot;）。</p><div class="tip custom-block"><p class="custom-block-title">安裝腳本做了什麼？</p><p>安裝腳本會：</p><ol><li>下載最新版本的 Plannotator CLI</li><li>加入系統路徑（PATH）</li><li>清理可能存在的舊版本</li><li>自動安裝 <code>/plannotator-review</code> 指令（用於程式碼審查）</li></ol></div><h3 id="第-2-步-設定-claude-code-可選" tabindex="-1">第 2 步：設定 Claude Code（可選） <a class="header-anchor" href="#第-2-步-設定-claude-code-可選" aria-label="Permalink to &quot;第 2 步：設定 Claude Code（可選）&quot;">​</a></h3><p>如果你使用 Claude Code，需要安裝外掛。</p><p><strong>在 Claude Code 中執行</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add backnotprop/plannotator</span></span>
<span class="line"><span>/plugin install plannotator@plannotator</span></span></code></pre></div><p><strong>重要</strong>：安裝外掛後，<strong>必須重新啟動 Claude Code</strong> 才能讓 hook 生效。</p><p><strong>你應該看到</strong>：外掛安裝成功後，Claude Code 的外掛清單中會出現 <code>plannotator</code>。</p><div class="info custom-block"><p class="custom-block-title">手動設定方式（可選）</p><p>如果你不想使用外掛系統，可以手動設定 hook。詳見 <a href="./../installation-claude-code/">Claude Code 外掛安裝</a> 章節。</p></div><h3 id="第-3-步-設定-opencode-可選" tabindex="-1">第 3 步：設定 OpenCode（可選） <a class="header-anchor" href="#第-3-步-設定-opencode-可選" aria-label="Permalink to &quot;第 3 步：設定 OpenCode（可選）&quot;">​</a></h3><p>如果你使用 OpenCode，需要編輯 <code>opencode.json</code> 檔案。</p><p><strong>編輯 <code>opencode.json</code></strong>：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://opencode.ai/config.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@plannotator/opencode@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>重新啟動 OpenCode</strong>。</p><p><strong>你應該看到</strong>：重新啟動後，OpenCode 會自動載入外掛，<code>submit_plan</code> 工具將可用。</p><h3 id="第-4-步-首次計畫審查-claude-code-範例" tabindex="-1">第 4 步：首次計畫審查（Claude Code 範例） <a class="header-anchor" href="#第-4-步-首次計畫審查-claude-code-範例" aria-label="Permalink to &quot;第 4 步：首次計畫審查（Claude Code 範例）&quot;">​</a></h3><p><strong>觸發條件</strong>：讓 Claude Code 產生一個實施計畫，並呼叫 <code>ExitPlanMode</code>。</p><p><strong>範例對話</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者：幫我寫一個使用者認證模組的實施計畫</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude：好的，這是實施計畫：</span></span>
<span class="line"><span>1. 建立使用者模型</span></span>
<span class="line"><span>2. 實作註冊 API</span></span>
<span class="line"><span>3. 實作登入 API</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>（呼叫 ExitPlanMode）</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><ol><li>瀏覽器自動開啟 Plannotator UI</li><li>顯示 AI 產生的計畫內容</li><li>可以選取計畫文字，新增註解（刪除、取代、評論）</li><li>底部有「Approve」和「Request Changes」按鈕</li></ol><p><strong>操作</strong>：</p><ol><li>瀏覽器檢視計畫</li><li>如果計畫沒問題，點擊 <strong>Approve</strong> → AI 繼續實施</li><li>如果需要修改，選取要改的文字，點擊 <strong>Delete</strong>、<strong>Replace</strong> 或 <strong>Comment</strong> → 點擊 <strong>Request Changes</strong></li></ol><p><strong>你應該看到</strong>：點擊後，瀏覽器會自動關閉，Claude Code 會收到你的決策並繼續執行。</p><h3 id="第-5-步-首次程式碼審查" tabindex="-1">第 5 步：首次程式碼審查 <a class="header-anchor" href="#第-5-步-首次程式碼審查" aria-label="Permalink to &quot;第 5 步：首次程式碼審查&quot;">​</a></h3><p><strong>在專案目錄中執行</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><ol><li>瀏覽器開啟程式碼審查頁面</li><li>顯示 Git diff（預設是未提交的變更）</li><li>左側是檔案樹，右側是 diff viewer</li><li>點擊行號可以選取程式碼範圍，新增註解</li></ol><p><strong>操作</strong>：</p><ol><li>在 diff viewer 中瀏覽程式碼變更</li><li>點擊行號選擇要審查的程式碼</li><li>在右側面板新增註解（comment/suggestion/concern）</li><li>點擊 <strong>Send Feedback</strong> 傳送給 agent，或點擊 <strong>LGTM</strong> 批准</li></ol><p><strong>你應該看到</strong>：點擊 Send Feedback 後，瀏覽器會關閉，終端機中會輸出格式化的回饋內容，agent 會自動處理。</p><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><p>完成以上步驟後，你應該能夠：</p><ul><li>[ ] 安裝腳本顯示 &quot;plannotator vX.X.X installed to ...&quot;</li><li>[ ] 在 Claude Code 中觸發計畫審查，瀏覽器自動開啟 UI</li><li>[ ] 在 UI 中選取計畫文字，新增註解</li><li>[ ] 點擊 Approve 或 Request Changes，看到瀏覽器關閉</li><li>[ ] 執行 <code>/plannotator-review</code>，看到程式碼審查介面</li><li>[ ] 在程式碼審查中新增行級註解，點擊 Send Feedback</li></ul><p><strong>如果某一步失敗</strong>，詳見：</p><ul><li><a href="./../installation-claude-code/">Claude Code 安裝指南</a></li><li><a href="./../installation-opencode/">OpenCode 安裝指南</a></li><li><a href="./../../faq/common-problems/">常見問題</a></li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><p><strong>常見錯誤 1</strong>：安裝後執行 <code>plannotator</code> 提示「command not found」</p><p><strong>原因</strong>：PATH 環境變數未更新，或需要重新啟動終端機。</p><p><strong>解決</strong>：</p><ul><li>macOS/Linux：執行 <code>source ~/.zshrc</code> 或 <code>source ~/.bashrc</code>，或重新啟動終端機</li><li>Windows：重新啟動 PowerShell 或 CMD</li></ul><p><strong>常見錯誤 2</strong>：Claude Code 安裝外掛後，計畫審查沒有觸發</p><p><strong>原因</strong>：未重新啟動 Claude Code，hook 未生效。</p><p><strong>解決</strong>：完全退出 Claude Code（不只是關閉視窗），然後重新開啟。</p><p><strong>常見錯誤 3</strong>：瀏覽器沒有自動開啟</p><p><strong>原因</strong>：可能是遠端模式（如 devcontainer、SSH），或者連接埠被佔用。</p><p><strong>解決</strong>：</p><ul><li>檢查是否設定了 <code>PLANNOTATOR_REMOTE=1</code> 環境變數</li><li>查看終端機輸出的 URL，手動在瀏覽器中開啟</li><li>詳見 <a href="./../../advanced/remote-mode/">遠端/Devcontainer 模式</a></li></ul><p><strong>常見錯誤 4</strong>：程式碼審查顯示「No changes」</p><p><strong>原因</strong>：目前沒有未提交的 git 變更。</p><p><strong>解決</strong>：</p><ul><li>先執行 <code>git status</code> 確認有變更</li><li>或執行 <code>git add</code> 暫存一些檔案</li><li>或切換到其他 diff 類型（如 last commit）</li></ul><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>Plannotator 是一個本機執行的審查工具，透過視覺化 UI 提升計畫審查和程式碼審查的效率：</p><p><strong>核心功能</strong>：</p><ul><li><strong>計畫審查</strong>：視覺化審查 AI 產生的計畫，支援精確註解</li><li><strong>程式碼審查</strong>：視覺化審查 Git diff，支援行級註解</li><li><strong>URL 分享</strong>：無需後端即可分享審查內容</li><li><strong>第三方整合</strong>：自動儲存批准的計畫到 Obsidian/Bear</li></ul><p><strong>核心優勢</strong>：</p><ul><li>本機執行，資料安全</li><li>視覺化 UI，提升效率</li><li>精確回饋，減少溝通成本</li><li>團隊協作，無需帳號系統</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../installation-claude-code/">Claude Code 外掛安裝</a></strong>。</p><p>你會學到：</p><ul><li>詳細的 Claude Code 外掛安裝步驟</li><li>手動設定 hook 的方法</li><li>如何驗證安裝是否成功</li><li>常見安裝問題的解決方法</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開檢視原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>CLI 入口（計畫審查）</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>1-50</td></tr><tr><td>CLI 入口（程式碼審查）</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L46-L84" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>46-84</td></tr><tr><td>計畫審查伺服器</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L1-L200" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>1-200</td></tr><tr><td>程式碼審查伺服器</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts#L1-L150" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></td><td>1-150</td></tr><tr><td>Git 工具</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L1-L100" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>1-100</td></tr><tr><td>計畫審查 UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>程式碼審查 UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>1-200</td></tr></tbody></table><p><strong>關鍵常數</strong>：</p><ul><li><code>MAX_RETRIES = 5</code>：連接埠重試次數（<code>packages/server/index.ts:80</code>）</li><li><code>RETRY_DELAY_MS = 500</code>：連接埠重試延遲（<code>packages/server/index.ts:80</code>）</li></ul><p><strong>關鍵函式</strong>：</p><ul><li><code>startPlannotatorServer()</code>：啟動計畫審查伺服器（<code>packages/server/index.ts</code>）</li><li><code>startReviewServer()</code>：啟動程式碼審查伺服器（<code>packages/server/review.ts</code>）</li><li><code>runGitDiff()</code>：執行 git diff 指令（<code>packages/server/git.ts</code>）</li></ul><p><strong>環境變數</strong>：</p><ul><li><code>PLANNOTATOR_REMOTE</code>：遠端模式標誌（<code>apps/hook/server/index.ts:17</code>）</li><li><code>PLANNOTATOR_PORT</code>：固定連接埠（<code>apps/hook/server/index.ts:18</code>）</li><li><code>PLANNOTATOR_BROWSER</code>：自訂瀏覽器（<code>apps/hook/README.md:79</code>）</li><li><code>PLANNOTATOR_SHARE</code>：URL 分享開關（<code>apps/hook/server/index.ts:44</code>）</li></ul></details>`,104)])])}const u=s(o,[["render",l]]);export{g as __pageData,u as default};
